        data: {"result": {"minY": 1.0, "minX": 0.0, "maxY": 5000000.0, "series": [{"data": [[300.0, 1.0]], "isOverall": false, "label": "01 DB Connection OK", "isController": false}, {"data": [[0.0, 1.0]], "isOverall": false, "label": "02 UI Components Exist", "isController": false}, {"data": [[0.0, 5000000.0]], "isOverall": false, "label": "Load Antenna By ID", "isController": false}, {"data": [[0.0, 4999998.0], [300.0, 1.0], [100.0, 1.0]], "isOverall": false, "label": "Load UI Component By ID", "isController": false}, {"data": [[0.0, 1.0]], "isOverall": false, "label": "04 Antenna Relations Valid", "isController": false}, {"data": [[0.0, 1.0]], "isOverall": false, "label": "05 UI Layout Load", "isController": false}, {"data": [[0.0, 1.0]], "isOverall": false, "label": "03 UI Coordinates Valid", "isController": false}], "supportsControllersDiscrimination": true, "granularity": 100, "maxX": 300.0, "title": "Response Time Distribution"}},
